import{_ as r,o,c as a,ai as t}from"./chunks/framework.o3ijFD2P.js";const g=JSON.parse('{"title":"项目介绍","description":"李晨煜 QQ空间说说备份项目介绍 - 基于 QzoneExporter 的完整备份方案","frontmatter":{"title":"项目介绍","description":"李晨煜 QQ空间说说备份项目介绍 - 基于 QzoneExporter 的完整备份方案"},"headers":[],"relativePath":"intro.md","filePath":"intro.md"}'),i={name:"intro.md"};function l(n,e,s,d,p,h){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="项目介绍" tabindex="-1">项目介绍 <a class="header-anchor" href="#项目介绍" aria-label="Permalink to “项目介绍”">​</a></h1><p>本项目是 <strong>李晨煜（绝赞stars我一生之敌）</strong> QQ空间说说的<strong>近一年完整备份</strong>（2025年4月～2026年4月）。</p><h2 id="备份缘起" tabindex="-1">备份缘起 <a class="header-anchor" href="#备份缘起" aria-label="Permalink to “备份缘起”">​</a></h2><p>2026年4月12日前后，李晨煜的QQ空间疑似开启了“访客仅能查看最近一年说说”的权限设置，导致更早期的说说内容对非好友访客不可见。<br> 为了避免多年积累的珍贵记忆再次面临丢失风险，作者决定对近一年的说说进行完整本地备份，并以 VitePress 静态站的形式长期保存。</p><p>所有说说已导出为 Markdown 格式，按 <strong>年/月</strong> 结构组织，支持图片本地化显示，可直接部署在 VitePress 静态站点上，方便永久存档、搜索与阅读。</p><h2 id="项目技术基础" tabindex="-1">项目技术基础 <a class="header-anchor" href="#项目技术基础" aria-label="Permalink to “项目技术基础”">​</a></h2><h3 id="qzoneexporter" tabindex="-1">QzoneExporter <a class="header-anchor" href="#qzoneexporter" aria-label="Permalink to “QzoneExporter”">​</a></h3><p>本备份主要基于开源项目 <strong>QzoneExporter</strong> 进行数据导出：</p><ul><li><strong>仓库地址</strong>：<a href="https://github.com/wwwpf/QzoneExporter" target="_blank" rel="noreferrer">https://github.com/wwwpf/QzoneExporter</a></li><li><strong>功能特点</strong>： <ul><li>支持导出说说、日志、相册、留言板等 QQ空间数据</li><li>自动下载说说和相册中的图片、视频至本地</li><li>将导出的数据以网页形式本地化展示（时间轴风格）</li><li>支持 Exif 信息写回等实用功能</li></ul></li></ul><p><strong>License</strong>：GPL-3.0 license</p><h2 id="本项目使用的自定义-python-脚本" tabindex="-1">本项目使用的自定义 Python 脚本 <a class="header-anchor" href="#本项目使用的自定义-python-脚本" aria-label="Permalink to “本项目使用的自定义 Python 脚本”">​</a></h2><p>为了让备份更适合 VitePress 阅读，我编写了以下辅助 Python 脚本：</p><h3 id="_1-主生成脚本-qqspace-fix-final-py" tabindex="-1">1. 主生成脚本（<code>qqspace_fix_final.py</code>） <a class="header-anchor" href="#_1-主生成脚本-qqspace-fix-final-py" aria-label="Permalink to “1. 主生成脚本（qqspace_fix_final.py）”">​</a></h3><ul><li>从 <code>shuoshuo_*.json</code> 文件中读取所有说说数据</li><li>严格按照 JSON 中的图片原始 URL 计算 <strong>MD5 短哈希</strong>，生成稳定、安全的文件名（<code>img_xxxxxxxx.jpeg</code>）</li><li>将图片从原始 <code>downloaded</code> 文件夹复制到 VitePress 的 <code>public/downloaded/</code> 目录（不破坏原始文件）</li><li>按 <strong>yyyy/mm/</strong> 目录结构生成独立的 <code>.md</code> 文件</li><li>每条说说包含 Front Matter、正文、图片展示、转发内容等</li><li>彻底解决 QQ空间图片防盗链问题</li></ul><h3 id="_2-图片复制与重命名脚本-fix-downloaded-copy-py" tabindex="-1">2. 图片复制与重命名脚本（<code>fix_downloaded_copy.py</code>） <a class="header-anchor" href="#_2-图片复制与重命名脚本-fix-downloaded-copy-py" aria-label="Permalink to “2. 图片复制与重命名脚本（fix_downloaded_copy.py）”">​</a></h3><ul><li>专门用于将已下载的图片批量复制到新目录</li><li>保证文件名与 Markdown 中引用的路径 <strong>100% 严格一致</strong></li><li>支持断点续复制，避免重复操作</li></ul><p>这些脚本已针对 VitePress 的构建特性进行优化（避免特殊字符导致的 Rollup 解析错误），文件名简洁、安全且稳定。</p><h2 id="项目特点" tabindex="-1">项目特点 <a class="header-anchor" href="#项目特点" aria-label="Permalink to “项目特点”">​</a></h2><ul><li><strong>完全本地化</strong>：所有图片均为本地文件，无需依赖 QQ空间服务器</li><li><strong>结构清晰</strong>：按年/月自动分类，方便浏览历史说说</li><li><strong>移动端友好</strong>：VitePress 默认支持响应式布局与暗黑模式</li><li><strong>搜索支持</strong>：可通过站点搜索快速找到包含关键词的说说</li><li><strong>长期可维护</strong>：后续可继续追加新说说，脚本可重复运行</li></ul><h2 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to “致谢”">​</a></h2><ul><li>感谢 <a href="https://github.com/wwwpf/QzoneExporter" target="_blank" rel="noreferrer">QzoneExporter</a> 项目提供的强大导出能力</li></ul><hr><p><strong>声明</strong>：<br> 本项目仅用于<strong>个人数据存档与回忆</strong>，不做任何商业用途。所有内容版权归原作者（李晨煜）所有。</p><p>如果你对备份脚本、部署方式或说说内容有任何疑问，欢迎在 GitHub Issue 中讨论。</p>',24)])])}const x=r(i,[["render",l]]);export{g as __pageData,x as default};
